188â†’    override fun resumeWith(result: Result<T>) {
189â†’        val state = result.toState()
190â†’        if (dispatcher.safeIsDispatchNeeded(context)) {
191â†’            _state = state
192â†’            resumeMode = MODE_ATOMIC
193â†’            dispatcher.safeDispatch(context, this)
194â†’        } else {
195â†’            executeUnconfined(state, MODE_ATOMIC) {
196â†’                withCoroutineContext(context, countOrElement) {
197â†’                    continuation.resumeWith(result)
198â†’                }
199â†’            }
