206â†’    internal inline fun resumeCancellableWith(result: Result<T>) {
207â†’        val state = result.toState()
208â†’        if (dispatcher.safeIsDispatchNeeded(context)) {
209â†’            _state = state
210â†’            resumeMode = MODE_CANCELLABLE
211â†’            dispatcher.safeDispatch(context, this)
212â†’        } else {
213â†’            executeUnconfined(state, MODE_CANCELLABLE) {
214â†’                if (!resumeCancelled(state)) {
215â†’                    resumeUndispatchedWith(result)
