226â†’            val cause = job.getCancellationException()
227â†’            cancelCompletedResult(state, cause)
228â†’            resumeWithException(cause)
229â†’            return true
230â†’        }
231â†’        return false
232â†’    }
233â†’
234â†’    @Suppress("NOTHING_TO_INLINE")
235â†’    internal inline fun resumeUndispatchedWith(result: Result<T>) {
236â†’        withContinuationContext(continuation, countOrElement) {
237â†’            continuation.resumeWith(result)
