252â†’internal fun CoroutineDispatcher.safeDispatch(context: CoroutineContext, runnable: Runnable) {
253â†’    try {
254â†’        dispatch(context, runnable)
255â†’    } catch (e: Throwable) {
256â†’        throw DispatchException(e, this, context)
257â†’    }
258â†’}
