260â†’internal fun CoroutineDispatcher.safeIsDispatchNeeded(context: CoroutineContext): Boolean {
261â†’    try {
262â†’        return isDispatchNeeded(context)
263â†’    } catch (e: Throwable) {
264â†’        throw DispatchException(e, this, context)
