268â†’/**
269â†’ * It is not inline to save bytecode (it is pretty big and used in many places)
270â†’ * and we leave it public so that its name is not mangled in use stack traces if it shows there.
271â†’ * It may appear in stack traces when coroutines are started/resumed with unconfined dispatcher.
272â†’ * @suppress **This an internal API and should not be used from general code.**
273â†’ */
274â†’@InternalCoroutinesApi
275â†’public fun <T> Continuation<T>.resumeCancellableWith(
276â†’    result: Result<T>,
277â†’): Unit = when (this) {
278â†’    is DispatchedContinuation -> resumeCancellableWith(result)
279â†’    else -> resumeWith(result)
280â†’}
