282â†’internal fun DispatchedContinuation<Unit>.yieldUndispatched(): Boolean =
283â†’    executeUnconfined(Unit, MODE_CANCELLABLE, doYield = true) {
284â†’        run()
285â†’    }
286â†’
287â†’/**
288â†’ * Executes given [block] as part of current event loop, updating current continuation
289â†’ * mode and state if continuation is not resumed immediately.
290â†’ * [doYield] indicates whether current continuation is yielding (to provide fast-path if event-loop is empty).
291â†’ * Returns `true` if execution of continuation was queued (trampolined) or `false` otherwise.
292â†’ */
293â†’private inline fun DispatchedContinuation<*>.executeUnconfined(
294â†’    contState: Any?, mode: Int, doYield: Boolean = false,
295â†’    block: () -> Unit
296â†’): Boolean {
297â†’    assert { mode != MODE_UNINITIALIZED } // invalid execution mode
298â†’    val eventLoop = ThreadLocalEventLoop.eventLoop
299â†’    // If we are yielding and unconfined queue is empty, we can bail out as part of fast path
300â†’    if (doYield && eventLoop.isUnconfinedQueueEmpty) return false
301â†’    return if (eventLoop.isUnconfinedLoopActive) {
302â†’        // When unconfined loop is active -- dispatch continuation for execution to avoid stack overflow
303â†’        _state = contState
304â†’        resumeMode = mode
305â†’        eventLoop.dispatchUnconfined(this)
306â†’        true // queued into the active loop
307â†’    } else {
308â†’        // Was not active -- run event loop until all unconfined tasks are executed
309â†’        runUnconfinedEventLoop(eventLoop, block = block)
310â†’        false
311â†’    }
312â†’}
