{"file_path":"/project/test_flow_hang_reproduction.kt","content":"package kotlinx.coroutines.test

import kotlinx.coroutines.*
import kotlinx.coroutines.flow.*
import kotlin.test.*

/**
 * Test to reproduce the flow hanging issue when dispatcher throws an exception.
 *
 * Steps to reproduce:
 * When using flowOn with a dispatcher that throws an exception (e.g., missing Main dispatcher),
 * the flow collection should throw the exception instead of silently hanging.
 */
fun main() {
    testFlowHangOnDispatcherException()
}

class FlowDispatcherExceptionTest {

    companion object {
        private var testPassed = false
    }

    @Test
    fun testFlowHangOnDispatcherException() {
        runBlocking {
            var caughtException: Throwable? = null

            // Create a dispatcher that throws when trying to access it
            val failingDispatcher = object : CoroutineDispatcher() {
                override fun dispatch(context: CoroutineContext, block: Runnable) {
                    throw IllegalArgumentException("Main dispatcher not available")
                }

                override fun isDispatchNeeded(context: CoroutineContext): Boolean = true
            }

            try {
                flowOf(1, 2, 3)
                    .flowOn(failingDispatcher)
                    .collect {
                        println("collect: $it")
                    }
            } catch (e: Exception) {
                caughtException = e
                println("Caught expected exception: $e")
            }

            if (caughtException == null) {
                throw AssertionError("Expected an exception to be thrown, but none was thrown")
            }

            if (caughtException !is IllegalArgumentException) {
                throw AssertionError("Expected IllegalArgumentException, got ${caughtException.javaClass}")
            }

            if (caughtException.message != "Main dispatcher not available") {
                throw AssertionError("Expected exception message 'Main dispatcher not available', got '${caughtException.message}'")
            }

            println("Test passed!")
        }
    }
}

// Simple test runner
fun testFlowHangOnDispatcherException() {
    val test = FlowDispatcherExceptionTest()
    test.testFlowHangOnDispatcherException()
}"}

