{"file_path":"/project/kotlinx-coroutines-core/common/test/flow/FlowDispatcherExceptionTest.kt","content":"package kotlinx.coroutines.flow

import kotlinx.coroutines.*
import kotlinx.coroutines.testing.*
import kotlin.test.*

/**
 * Tests for flow collection when dispatchers throw exceptions.
 */
class FlowDispatcherExceptionTest : TestBase() {

    @Test
    fun testFlowOnDispatcherException() = runTest {
        // Create a dispatcher that throws when trying to access it
        val failingDispatcher = object : CoroutineDispatcher() {
            override fun dispatch(context: CoroutineContext, block: Runnable) {
                throw IllegalArgumentException("Main dispatcher not available")
            }

            override fun isDispatchNeeded(context: CoroutineContext): Boolean = true
        }

        var caughtException: Throwable? = null
        try {
            flowOf(1, 2, 3)
                .flowOn(failingDispatcher)
                .collect {
                    // Should not reach here
                    fail("Should not collect any values")
                }
        } catch (e: Exception) {
            caughtException = e
        }

        assertNotNull(caughtException, "Expected an exception to be thrown")
        assertTrue(caughtException is IllegalArgumentException, "Expected IllegalArgumentException, got ${caughtException!!.javaClass}")
        assertEquals("Main dispatcher not available", caughtException!!.message, "Expected exception message 'Main dispatcher not available'")
    }

    @Test
    fun testFlowOnDispatcherExceptionInSafeDispatchNeeded() = runTest {
        // Create a dispatcher that throws when checking if dispatch is needed
        val failingDispatcher = object : CoroutineDispatcher() {
            override fun dispatch(context: CoroutineContext, block: Runnable) {
                // This shouldn't be called
                throw IllegalStateException("Unexpected dispatch call")
            }

            override fun isDispatchNeeded(context: CoroutineContext): Boolean {
                throw RuntimeException("Failed to check dispatch needed")
            }
        }

        var caughtException: Throwable? = null
        try {
            flowOf(1, 2, 3)
                .flowOn(failingDispatcher)
                .collect {
                    // Should not reach here
                    fail("Should not collect any values")
                }
        } catch (e: Exception) {
            caughtException = e
        }

        assertNotNull(caughtException, "Expected an exception to be thrown")
        assertTrue(caughtException is RuntimeException, "Expected RuntimeException, got ${caughtException!!.javaClass}")
        assertEquals("Failed to check dispatch needed", caughtException!!.message)
    }

    @Test
    fun testFlowOnNormalDispatcherWorks() = runTest {
        // Verify normal operation still works
        val values = mutableListOf<Int>()
        flowOf(1, 2, 3)
            .flowOn(Dispatchers.Default)
            .collect {
                values.add(it)
            }

        assertEquals(listOf(1, 2, 3), values)
    }
}"}

