 */
fun main() = runBlocking {
    println("Starting test for flow hang fix...")

    // Test 1: Flow with dispatcher that throws on dispatch
    println("\nTest 1: Flow with dispatcher that throws on dispatch")
    try {
        val failingDispatcher = object : CoroutineDispatcher() {
            override fun dispatch(context: CoroutineContext, block: Runnable) {
                throw IllegalArgumentException("Main dispatcher not available")
            }

            override fun isDispatchNeeded(context: CoroutineContext): Boolean = true
        }

        flowOf(1, 2, 3)
            .flowOn(failingDispatcher)
            .collect {
                println("ERROR: Should not collect any values but got: $it")
            }
        println("ERROR: Should have thrown an exception but didn't")
        exitProcess(1)
    } catch (e: Exception) {
        if (e is IllegalArgumentException && e.message == "Main dispatcher not available") {
            println("âś“ PASSED: Correctly caught expected exception: ${e.message}")
        } else {
            println("ERROR: Caught wrong exception: ${e.javaClass} - ${e.message}")
            exitProcess(1)
        }
    }

    // Test 2: Flow with dispatcher that throws on isDispatchNeeded
    println("\nTest 2: Flow with dispatcher that throws on isDispatchNeeded")
    try {
        val failingDispatcher = object : CoroutineDispatcher() {
            override fun dispatch(context: CoroutineContext, block: Runnable) {
                throw IllegalStateException("Unexpected dispatch call")
            }

            override fun isDispatchNeeded(context: CoroutineContext): Boolean {
                throw RuntimeException("Failed to check dispatch needed")
            }
        }

        flowOf(1, 2, 3)
            .flowOn(failingDispatcher)
            .collect {
                println("ERROR: Should not collect any values but got: $it")
            }
        println("ERROR: Should have thrown an exception but didn't")
        exitProcess(1)
    } catch (e: Exception) {
        if (e is RuntimeException && e.message == "Failed to check dispatch needed") {
            println("âś“ PASSED: Correctly caught expected exception: ${e.message}")
        } else {
            println("ERROR: Caught wrong exception: ${e.javaClass} - ${e.message}")
            exitProcess(1)
        }
    }

    // Test 3: Normal flow operation still works
    println("\nTest 3: Normal flow operation")
    try {
        val values = mutableListOf<Int>()
        flowOf(1, 2, 3)
            .flowOn(Dispatchers.Default)
            .collect {
                values.add(it)
            }
        if (values == listOf(1, 2, 3)) {
            println("âś“ PASSED: Normal flow operation works correctly")
        } else {
            println("ERROR: Expected [1, 2, 3] but got $values")
            exitProcess(1)
        }
    } catch (e: Exception) {
        println("ERROR: Normal flow operation should not throw but got: ${e.javaClass} - ${e.message}")
        exitProcess(1)
    }

    println("\nâś“ ALL TESTS PASSED!")
}"}

